    "style": "ultra-realistic, 8K, high-detail, cinematic portrait photography",
    "subject": {
      "type": "young woman",
      "reference_image": "use uploaded image as primary facial and identity reference",
      "pose": {
        "description": "standing confidently, slightly leaning against a counter",
        "body_language": "relaxed yet self-assured, shoulders back, head slightly tilted",
